// Unstop public search API (verified live 2026-07-13; ~10k internships total).
const terms = [
  { q: 'product', role_hint: 'pm' },
  { q: 'marketing', role_hint: 'growth' },
  { q: 'growth', role_hint: 'growth' },
  { q: 'data analyst', role_hint: 'analyst' },
  { q: 'business analyst', role_hint: 'analyst' },
  { q: 'software', role_hint: 'swe' },
  { q: 'developer', role_hint: 'swe' },
];
return terms.map(t => ({ json: {
  role_hint: t.role_hint,
  api_url: `https://unstop.com/api/public/opportunity/search-result?opportunity=internships&oppstatus=open&per_page=40&page=1&searchTerm=${encodeURIComponent(t.q)}`
}}));

// Flatten Unstop's response into postings; keep only open registrations.
const strip = h => String(h || '').replace(/<[^>]+>/g, ' ').replace(/\s+/g, ' ').trim();
const searches = $('Search API calls').all();
const out = [];
const seen = new Set();
$input.all().forEach((item, i) => {
  const hint = searches[i] ? searches[i].json.role_hint : 'other';
  const list = (item.json.data && item.json.data.data) || [];
  for (const o of list) {
    const url = o.seo_url || (o.public_url ? 'https://unstop.com/' + o.public_url : null);
    if (!url || seen.has(url)) continue;
    // skip if registration already closed
    const rr = o.regnRequirements || {};
    if (rr.reg_status === 'FINISHED' || (typeof rr.remaining_time === 'number' && rr.remaining_time < 0)) continue;
    seen.add(url);
    const jd = o.jobDetail || {};
    const cities = (o.locations || []).map(l => l.city).filter(Boolean);
    const skills = (o.required_skills || []).map(s => s.skill_name || s.skill).filter(Boolean);
    const facts = [
      'Title: ' + (o.title || ''),
      'Company: ' + ((o.organisation && o.organisation.name) || ''),
      'Locations: ' + (cities.join(', ') || (o.region === 'online' ? 'Remote/Online' : jd.type || '')),
      'Work type: ' + (jd.type || '') + ' ' + (jd.timing || ''),
      jd.not_disclosed ? 'Stipend: not disclosed' : `Stipend: ${jd.min_salary || 0}-${jd.max_salary || 0} INR per ${jd.pay_in || 'month'} (${jd.paid_unpaid || ''})`,
      'Listed skills: ' + skills.join(', '),
      'Posted/approved: ' + (o.approved_date || o.updated_at || ''),
      'Description: ' + strip(o.details).slice(0, 4500)
    ].join('\n');
    out.push({ json: {
      source: 'unstop',
      source_url: url,
      company: (o.organisation && o.organisation.name) || null,
      role_hint: hint,
      raw_text: facts.slice(0, 6000)
    }});
  }
});
return out;

const known = new Set(
  $('Fetch known URLs').all().map(i => i.json.source_url).filter(Boolean)
);
return $('Normalize + filter open').all().filter(i => !known.has(i.json.source_url));

const SYSTEM = 'You extract structured data from internship job postings in India. Output ONLY a valid JSON object, no markdown fences, no commentary. If a field is not stated use null (arrays: [], booleans: false). Never guess stipend numbers. Schema: {"title":string,"company":string,"role_category":"pm"|"growth"|"analyst"|"swe"|"other","location":string|null,"city":string|null,"is_remote":boolean,"stipend_min_inr":integer|null,"stipend_max_inr":integer|null,"duration_months":number|null,"yoe_required":number,"ppo_offered":boolean,"posted_at":"YYYY-MM-DD"|null,"skills":[string],"perks":[string]}. Rules: stipend is monthly INR ("8-12k" -> min 8000 max 12000; "unpaid" -> 0; convert lakhs/year or annual pay to monthly). city: one normalized Indian city (Bangalore, Mumbai, Delhi NCR, Hyderabad, Pune, Chennai, Kolkata, or the proper city name), null if remote-only. yoe_required: years of prior experience asked, 0 if none mentioned. posted_at: resolve relative dates against the given today date. skills: lowercase canonical tags (excel, sql, power bi, google analytics, figma, a/b testing, seo, python, react, communication...), exclude generic filler like "hardworking". role_category: pm=product roles, growth=marketing/growth/community, analyst=data/business/product analyst, swe=software/web/app/backend/frontend/qa/devops/ml engineering, else other.';
const today = new Date().toISOString().slice(0, 10);
return $input.all().map(item => ({ json: {
  ...item.json,
  anthropic_body: {
    model: 'claude-haiku-4-5',
    max_tokens: 1024,
    temperature: 0,
    system: SYSTEM,
    messages: [{ role: 'user', content: `Today's date: ${today}\n\nPosting URL: ${item.json.source_url}\nPosting text:\n---\n${item.json.raw_text}\n---` }]
  }
}}));

const reqs = $('Build Claude request').all();
const out = [];
$input.all().forEach((item, i) => {
  try {
    const txt = (item.json.content && item.json.content[0] && item.json.content[0].text) || '';
    const j = JSON.parse(txt.replace(/^```json\s*/i, '').replace(/```\s*$/, '').trim());
    const meta = reqs[i] ? reqs[i].json : {};
    out.push({ json: {
      source: 'unstop',
      source_url: meta.source_url,
      raw_text: meta.raw_text,
      title: j.title,
      company: j.company || meta.company,
      role_category: ['pm','growth','analyst','swe','other'].includes(j.role_category) ? j.role_category : (meta.role_hint || 'other'),
      location: j.location,
      city: j.city,
      is_remote: !!j.is_remote,
      stipend_min_inr: Number.isFinite(j.stipend_min_inr) ? Math.round(j.stipend_min_inr) : null,
      stipend_max_inr: Number.isFinite(j.stipend_max_inr) ? Math.round(j.stipend_max_inr) : null,
      duration_months: j.duration_months,
      yoe_required: Number.isFinite(j.yoe_required) ? j.yoe_required : 0,
      ppo_offered: typeof j.ppo_offered === 'boolean' ? j.ppo_offered : null,
      posted_at: /^\d{4}-\d{2}-\d{2}$/.test(j.posted_at || '') ? j.posted_at : null,
      skills: Array.isArray(j.skills) ? j.skills.map(s => String(s).toLowerCase().trim()) : [],
      perks: Array.isArray(j.perks) ? j.perks : [],
      extraction_model: 'claude-haiku-4-5',
      extraction_json: j
    }});
  } catch (e) { /* skip unparseable; retried next run since URL was never inserted */ }
});
return out;
